    nkjv: {
      "Genesis 35:10": "Also God said to him: \u201cYour name is Jacob; your name shall not be called Jacob anymore, but Israel shall be your name.\u201d So He called his name Israel.",
      "John 3:16": "For God so loved the world that He gave His only begotten Son, that whoever believes in Him should not perish but have everlasting life.",
      "John 1:14": "And the Word became flesh and dwelt among us, and we beheld His glory, the glory as of the only begotten of the Father, full of grace and truth.",
      "Matthew 1:23": "\u201cBehold, the virgin shall be with child, and bear a Son, and they shall call His name Immanuel,\u201d which is translated, \u201cGod with us.\u201d",
      "Luke 1:17": "He will also go before Him in the spirit and power of Elijah, \u2018to turn the hearts of the fathers to the children,\u2019 and the disobedient to the wisdom of the just, to make ready a people prepared for the Lord.",
    },
    blocks: [
      { type: "para", segments: [
        { t: "bold-italic", v: "Thus says The Lord to the peoples of the earth:" },
        { t: "text", v: " In My right hand is the power to save; and in My left, judgment, which I am about to pour out. For I am The Lord your God, The Only God, The God of Abraham, The God of Isaac, and of Jacob whose name is Israel." },
        { t: "fn", v: "1" },
        { t: "text", v: " And behold, I sent My Only Begotten into the world," },
        { t: "fn", v: "2" },
        { t: "text", v: " and The Word became flesh," },
        { t: "fn", v: "3" },
        { t: "text", v: " YahuShua, Immanu El." },
        { t: "fn", v: "4" },
      ]},
      { type: "para", segments: [
        { t: "text", v: "Again, I am sending The Holy One to you. Therefore incline your ears and listen, that you may receive true knowledge. For as it was at the first, so shall it be at the last, for I do not change." },
      ]},
      { type: "para", segments: [
        { t: "text", v: "Behold, ahead of The Messiah did I send John the Baptist, the voice of one crying out in the wilderness." },
        { t: "fn", v: "5" },
        { t: "text", v: " In John\u2019s hand I had placed the trumpet; and he made the path straight in preparation of The One coming after him, by whom all must be saved. John indeed baptized with water and with the Word given him. And now I am sending 144,000," },
        { t: "fn", v: "6" },
        { t: "text", v: " in the spirit of John and in the power of Elijah," },
        { t: "fn", v: "7" },
        { t: "text", v: " to baptize with the Word of God and fire. For I have placed My words in their mouths, and the Trumpet rests securely in their hands." },
      ]},
      { type: "para", segments: [
        { t: "text", v: "Therefore trust these I have sent and am sending, for they are My witnesses; they hear My voice and prepare My way before Me. For My judgments shall fall from Heaven, upon every tribe, tongue, people and nation; My punishments shall rain down hard upon the earth and break the pride of man! Behold, I shall remove all from their places; in My fierce anger I shall drive them out! The cities shall be laid waste and the houses shall be left desolate, for the earth shall become one vast desolation!" },
      ]},
      { type: "poetry", lines: [
        [{ t: "text", v: "Yet there is sanctuary from this storm," }],
        [{ t: "text", v: "A way of escape has been provided;" }],
        [{ t: "stanza-break" }],
        [{ t: "text", v: "For He is called Jesus and Christ;" }],
        [{ t: "text", v: "YahuShua" }, { t: "fn", v: "8" }, { t: "text", v: " HaMashiach is His name!..." }],
        [{ t: "stanza-break" }],
        [{ t: "text", v: "Call upon Him, do not wait!..." }],
        [{ t: "stanza-break" }],
        [{ t: "text", v: "Call upon His name in sincerity and in truth," }],
        [{ t: "text", v: "And you shall surely be delivered..." }],
      ]},
      { type: "closing", text: "Says The Lord." },
    ],
    prevLetter: { id: "hearts-changed", title: "Hearts Changed" },
    nextLetter: { id: "the-mark", title: "The Mark" },
