    footnotes: {},
    nkjv: {},
    blocks: [
      { type: "para", segments: [
        { t: "caps", v: "WOE TO THOSE WHO HARM THE LITTLE ONES! WOE TO THOSE WHO SLAUGHTER MY GIFTS! AND WOE TO ALL WHO STAND IN AGREEMENT!" },
        { t: "text", v: " Says The Lord. For they are and were created, sculpted delicately in fragile flesh, attached to The Vine before their very conception. For it is the fool who says in her heart, " },
        { t: "italic", v: "“There is no God,”" },
        { t: "text", v: " believing she answers only to herself, as she testifies aloud, saying, " },
        { t: "italic", v: "“It is my body, my choice.”" },
        { t: "text", v: " " },
        { t: "caps", v: "YOU CHOOSE DEATH!" },
        { t: "text", v: " Says The Lord. For the child within you is Mine, even as you are Mine also; your body is not your own! " },
        { t: "caps", v: "ALL BELONG TO THE LORD, ALL ANSWER TO ME!" },
      ]},
      { type: "para", segments: [
        { t: "bold-italic", v: "Therefore, thus says The Lord:" },
        { t: "text", v: " The murder of the innocent leads to the death of the guilty, who carry the innocent within them; take no part in their sin. For all who do wear equally the guilt of the mother, all seek the penalty of death; from the lawmakers to the voters, to the building owner to the workers to the suppliers, and finally to the father, if he does not take a stand to protect the unborn who are without blame. Behold, they have brought the wrath of God upon their nation, upon their state and upon their cities, calamity upon calamity until I have laid them waste!" },
      ]},
      { type: "poetry", lines: [
        [{ t: "italic", v: "Fierce is My anger, hot is My countenance!" }],
        [{ t: "italic", v: "My little ones perish in all the earth!" }],
        [{ t: "stanza-break" }],
        [{ t: "caps", v: "WHOLE GENERATIONS SLAUGHTERED!" }],
        [{ t: "caps", v: "MULTITUDES OF CHILDREN MURDERED" }],
        [{ t: "caps", v: "DAY AND NIGHT, WITHOUT CEASING!..." }],
        [{ t: "stanza-break" }],
        [{ t: "italic", v: "Therefore have I brought forth and appointed" }],
        [{ t: "italic", v: "Many days of sorrow for THIS generation!..." }],
        [{ t: "stanza-break" }],
        [{ t: "caps", v: "JUDGMENT!..." }],
        [{ t: "stanza-break" }],
        [{ t: "caps", v: "THE GREAT AND TERRIBLE DAY OF THE LORD!" }],
      ]},
    ],
    prevLetter: { id: "all-have-been-purchased", title: "All Have Been Purchased... Yet Few Have Accepted, Few Are Chosen" },
